/**
 * @summary Get recent orders for dashboard
 */
export const getGetRecentOrdersUrl = (params?: GetRecentOrdersParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/dashboard/recent-orders?${stringifiedParams}`
    : `/api/dashboard/recent-orders`;
};

export const getRecentOrders = async (
  params?: GetRecentOrdersParams,
  options?: RequestInit,
): Promise<Order[]> => {
  return customFetch<Order[]>(getGetRecentOrdersUrl(params), {
    ...options,
    method: "GET",
  });
};

